import{_ as e,a,b as o,c as s,d as i}from"./chunks/sidebar-usage-limit.DcfHb4Cn.js";import{_ as n}from"./chunks/sidebar-schedule-dates.AtfrOwJ1.js";import{_ as r,c as l,o as c,ag as u}from"./chunks/framework.DD2hp6gW.js";const p="/assets/selection-bogo-advanced.-Eo3iKSM.png",d="/assets/bogo-advanced-tiers-empty.KFCh-qac.png",g="/assets/bogo-advanced-tiers-example.BeTzOGkw.png",h="/assets/bogo-advanced-show-message.DpHBYce6.png",m="/assets/bogo-advanced-product-message-format.DsYDiRwh.png",f="/assets/bogo-advanced-cart-message-format.b2op7CxP.png",y="/assets/bogo-advanced-cart-message-location.BMcwXmbl.png",G=JSON.parse('{"title":"Campaign Type: BOGO Advanced (Buy X Get Y)","description":"","frontmatter":{},"headers":[],"relativePath":"campaigns/bogo-advanced-discounts.md","filePath":"campaigns/bogo-advanced-discounts.md","lastUpdated":null}'),b={name:"campaigns/bogo-advanced-discounts.md"};function v(_,t,S,q,C,O){return c(),l("div",null,t[0]||(t[0]=[u('<h1 id="campaign-type-bogo-advanced-buy-x-get-y" tabindex="-1">Campaign Type: BOGO Advanced (Buy X Get Y) <a class="header-anchor" href="#campaign-type-bogo-advanced-buy-x-get-y" aria-label="Permalink to &quot;Campaign Type: BOGO Advanced (Buy X Get Y)&quot;">​</a></h1><p>A <strong>BOGO Advanced (Buy X, Get Y)</strong> discount is a powerful upgrade to the standard BOGO campaign. While the standard BOGO requires the customer to buy and get the <em>same</em> product (Buy T-Shirt, Get T-Shirt), the Advanced version deals with <em>different</em> products.</p><p>This is perfect for cross-selling and bundling scenarios like:</p><ul><li>&quot;Buy a <strong>Laptop</strong>, Get a <strong>Mouse</strong> for Free&quot;</li><li>&quot;Buy 2 <strong>Jeans</strong>, Get a <strong>Belt</strong> at 50% Off&quot;</li></ul><h2 id="step-1-select-your-campaign-type" tabindex="-1">Step 1: Select Your Campaign Type <a class="header-anchor" href="#step-1-select-your-campaign-type" aria-label="Permalink to &quot;Step 1: Select Your Campaign Type&quot;">​</a></h2><p>To begin, navigate to <strong>CampaignBay → Add Campaign</strong>.</p><p><img src="'+p+'" alt="Select BOGO Advanced"></p><ul><li><strong>Select Discount Type:</strong> Choose <strong><code>BOGO Advanced</code></strong> from the list of available campaign types. This will unlock the specific configuration fields for Buy X Get Y offers.</li></ul><p><img src="'+e+'" alt="Campaign Title"></p><ul><li><strong>Campaign Title:</strong> Give your campaign a descriptive name (e.g., &quot;Free Mouse with Laptop Bundle&quot;). This name will appear in the &quot;All Campaigns&quot; list and can be used in your cart messages using the <code>{title}</code> placeholder.</li></ul><p><img src="'+a+'" alt="Save Actions"></p><ul><li><strong>Set Status:</strong> Ensure the status is set to <strong>Active</strong> to make the campaign live immediately upon saving.</li></ul><h2 id="step-2-define-the-bogo-tiers" tabindex="-1">Step 2: Define the BOGO Tiers <a class="header-anchor" href="#step-2-define-the-bogo-tiers" aria-label="Permalink to &quot;Step 2: Define the BOGO Tiers&quot;">​</a></h2><p>This is where you define the &quot;Buy X Get Y&quot; logic. You can create multiple tiers to encourage bulk purchases.</p><p><img src="'+d+'" alt="BOGO Advanced Tiers"></p><h3 id="configuration-fields" tabindex="-1">Configuration Fields <a class="header-anchor" href="#configuration-fields" aria-label="Permalink to &quot;Configuration Fields&quot;">​</a></h3><ol><li><strong>Buy Quantity:</strong> Enter how many items the customer must purchase to trigger the deal.</li><li><strong>Buy Product:</strong> Select the specific product the customer must purchase.</li><li><strong>Get Quantity:</strong> Enter how many of the &quot;Get Product&quot; they will receive.</li><li><strong>Get Product:</strong> Select the product the customer will receive as a discount.</li></ol><p><img src="'+g+'" alt="BOGO Advanced Tiers Example"></p><h3 id="example-the-laptop-bundle" tabindex="-1">Example: The &quot;Laptop Bundle&quot; <a class="header-anchor" href="#example-the-laptop-bundle" aria-label="Permalink to &quot;Example: The &quot;Laptop Bundle&quot;&quot;">​</a></h3><p>You want to give a free mouse with every laptop purchase.</p><ul><li><strong>Buy Product:</strong> Laptop Pro X</li><li><strong>Buy Quantity:</strong> 1</li><li><strong>Get Product:</strong> Wireless Mouse</li><li><strong>Get Quantity:</strong> 1</li></ul><p>When a customer adds <strong>1 Laptop Pro X</strong> to their cart, the system will automatically add <strong>1 Wireless Mouse</strong> to the cart for free (depending on your display settings).</p><h2 id="step-3-set-conditions-optional" tabindex="-1">Step 3: Set Conditions (Optional) <a class="header-anchor" href="#step-3-set-conditions-optional" aria-label="Permalink to &quot;Step 3: Set Conditions (Optional)&quot;">​</a></h2><p>You can add specific rules to restrict who can use this discount.</p><p><img src="'+o+'" alt="Conditions Overview"></p><p><strong><a href="./../core-concepts/conditions.html">Read the Full Guide: How to Use Conditions →</a></strong></p><h2 id="step-4-set-other-configurations-optional" tabindex="-1">Step 4: Set Other Configurations (Optional) <a class="header-anchor" href="#step-4-set-other-configurations-optional" aria-label="Permalink to &quot;Step 4: Set Other Configurations (Optional)&quot;">​</a></h2><p>This section provides additional rules for your campaign.</p><p><img src="'+s+'" alt="Exclude Sale Item"></p><ul><li><strong>Exclude Sale Items:</strong> Check this box if you do not want this campaign&#39;s discount to apply to products that are already on sale in WooCommerce. This is useful for preventing &quot;double discounting.&quot;</li></ul><p><img src="'+i+'" alt="Enable Usage Limit"></p><ul><li><strong>Enable Usage Limit:</strong> Check this box to set a maximum number of times this campaign can be used across your entire store. Once the limit is reached, the campaign will automatically become inactive.</li></ul><h2 id="step-5-set-the-schedule-optional" tabindex="-1">Step 5: Set the Schedule (Optional) <a class="header-anchor" href="#step-5-set-the-schedule-optional" aria-label="Permalink to &quot;Step 5: Set the Schedule (Optional)&quot;">​</a></h2><p>For a Scheduled Discount, setting the duration is essential. This section controls when your campaign will automatically start and end.</p><p><img src="'+n+'" alt="Enable Schedule"></p><ul><li><strong>Start Time / End Time:</strong> Use the date and time pickers to set the exact moment for the campaign to activate and expire.</li></ul><div class="tip custom-block"><p class="custom-block-title">Timezone Information</p><p>All dates and times are based on the timezone you have configured in your main WordPress settings under <strong>Settings → General → Timezone</strong>. The system automatically handles all UTC conversions for you.</p></div><div class="info custom-block"><p class="custom-block-title">Learn More About Automation</p><p>The status of your campaign is closely tied to the scheduling system, which uses WordPress Cron to automate activation and expiration.</p><p><strong><a href="./../core-concepts/scheduling-and-automation.html">Read the Full Guide: Scheduling &amp; Automation →</a></strong></p></div><h2 id="step-6-display-configurations" tabindex="-1">Step 6: Display Configurations <a class="header-anchor" href="#step-6-display-configurations" aria-label="Permalink to &quot;Step 6: Display Configurations&quot;">​</a></h2><ul><li><strong>Automatically Add Free Product To Cart:</strong><ul><li><strong>Checked (Recommended):</strong> The &quot;Get Product&quot; acts as a gift and is auto-added.</li><li><strong>Unchecked:</strong> The customer must manually add the &quot;Get Product&quot; to their cart to see the discount.</li></ul></li></ul><h3 id="messaging-options" tabindex="-1">Messaging Options <a class="header-anchor" href="#messaging-options" aria-label="Permalink to &quot;Messaging Options&quot;">​</a></h3><p><img src="'+h+'" alt="Show Promo Message"></p><ul><li><strong>Show BOGO Promotional Message at product page:</strong> Toggle this to enable or disable the custom message on the product page.</li></ul><p><img src="'+m+'" alt="Product Page Message"></p><ul><li><strong>Product Page Discount Message Format:</strong> Enter a message to display on the product page. Use placeholders like <code>{buy_quantity}</code>, <code>{get_quantity}</code>, and <code>{get_product_name}</code> to inform customers about the deal.</li></ul><p><img src="'+f+'" alt="Cart Page Message"></p><ul><li><strong>Cart Page Discount Message Format:</strong> Enter a message to display in the cart. You can use <code>{title}</code> for the campaign name and <code>{buy_product_name}</code> to specify what they bought.</li></ul><p><img src="'+y+'" alt="Cart Message Location"></p><ul><li><strong>Cart Page Message Location:</strong> Choose where the cart message should appear (e.g., next to the line item name).</li></ul><h2 id="step-7-save-the-campaign" tabindex="-1">Step 7: Save the Campaign <a class="header-anchor" href="#step-7-save-the-campaign" aria-label="Permalink to &quot;Step 7: Save the Campaign&quot;">​</a></h2><p>Once you have configured all the options, click the <strong>Save Campaign</strong> button. You will be redirected to the &quot;All Campaigns&quot; list.</p><p>Next, learn how to offer discounts based on other products in the cart.</p><ul><li><strong><a href="./product-in-cart-discounts.html">Product In Cart →</a></strong></li></ul>',53)]))}const x=r(b,[["render",v]]);export{G as __pageData,x as default};
